import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        name: 'Conversion',
        data: [10000, 6400, 3800, 2200, 1100, 420],
      },
    ],
    options: {
      chart: {
        type: 'funnel',
        height: 400,
        dropShadow: {
          enabled: true,
        },
      },
      plotOptions: {
        funnel: {
          shape: 'trapezoid',
          lastShape: 'flat',
        },
        bar: {
          barHeight: '90%',
          distributed: true,
        },
      },
      colors: [
        '#3b82f6',
        '#00a3f4',
        '#00b7b8',
        '#00c161',
        '#93bd00',
        '#ffa600',
      ],
      dataLabels: {
        enabled: true,
        formatter: function (val, opt) {
          // narrow segments only fit the value; the tooltip still shows the stage name
          if (val < 2000) return val
          return opt.w.globals.labels[opt.dataPointIndex] + ': ' + val
        },
        style: {
          colors: ['#fff'],
          fontSize: '14px',
          fontWeight: 600,
        },
      },
      title: {
        text: 'Sales Funnel: Trapezoid',
        align: 'middle',
      },
      xaxis: {
        categories: [
          'Visits',
          'Signups',
          'Activated',
          'Engaged',
          'Trial',
          'Paid',
        ],
      },
      legend: {
        show: false,
      },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="funnel"
          height={400}
        />
      </div>
    </div>
  )
}

export default ApexChart
